ate_dim ON d_date_sk=ws_sold_date_sk                       LEFT JOIN web_returns ON (ws_order_number=wr_order_number                                             AND ws_item_sk=wr_item_sk)        WHERE i_category='Sports'        and ws_sales_price / ws_list_price BETWEEN 77 * 0.01 AND 97 * 0.01        and wr_reason_sk in (59, 63, 65, 68, 70)) sales_detail GROUP BY d_year, i_brand_id, i_class_id, i_category_id, i_manufact_id)  SELECT  prev_yr.d_year AS prev_year                           ,curr_yr.d_year AS year                           ,curr_yr.i_brand_id                           ,curr_yr.i_class_id                           ,curr_yr.i_category_id                           ,curr_yr.i_manufact_id                           ,prev_yr.sales_cnt AS prev_yr_cnt                           ,curr_yr.sales_cnt AS curr_yr_cnt                           ,curr_yr.sales_cnt-prev_yr.sales_cnt AS sales_cnt_diff                           ,curr_yr.sales_amt-prev_yr.sales_amt AS sales_amt_diff  FROM all_sales curr_yr, all_sales prev_yr  WHERE curr_yr.i_brand_id=prev_yr.i_brand_id    AND curr_yr.i_class_id=prev_yr.i_class_id    AND curr_yr.i_category_id=prev_yr.i_category_id    AND curr_yr.i_manufact_id=prev_yr.i_manufact_id    AND curr_yr.d_year=1999    AND prev_yr.d_year=1999-1    AND prev_yr.sales_cnt > 0    AND CAST(curr_yr.sales_cnt AS DECIMAL(17,2))/CAST(prev_yr.sales_cnt AS DECIMAL(17,2))<0.9  ORDER BY sales_cnt_diff,sales_amt_diff  limit 100;

/*+ NO_MATERIALIZE(ssr) NO_MATERIALIZE(csr) NO_MATERIALIZE(wsr) */
with ssr AS ( /*+ HashJoin(store_sales item) */
select  s_store_id as store_id,           sum(ss_ext_sales_price) as sales,           sum(coalesce(sr_return_amt, 0)) as returns,           sum(ss_net_profit - coalesce(sr_net_loss, 0)) as profit   from store_sales left outer join store_returns on          (ss_item_sk = sr_item_sk and ss_ticket_number = sr_ticket_number),      date_dim,      store,      item,      promotion  where ss_sold_date_sk = d_date_sk        and d_date between cast('1999-09-24' as date)                   and cast('1999-09-24' as date) + interval '30' day        and ss_store_sk = s_store_sk        and ss_item_sk = i_item_sk        and i_current_price > 50        and ss_promo_sk = p_promo_sk        and p_channel_email = 'N'        and p_channel_tv = 'N'        and p_channel_radio = 'Y'        and p_channel_press = 'N'        and p_channel_event = 'Y'        and ss_wholesale_cost BETWEEN 33 AND 48        and i_category IN ('Home', 'Men')  group by s_store_id)  ,  csr AS ( /*+ HashJoin(catalog_sales item) */
select  cp_catalog_page_id as catalog_page_id,           sum(cs_ext_sales_price) as sales,           sum(coalesce(cr_return_amount, 0)) as returns,           sum(cs_net_profit - coalesce(cr_net_loss, 0)) as profit   from catalog_sales left outer join catalog_returns on          (cs_item_sk = cr_item_sk and cs_order_number = cr_order_number),      date_dim,      catalog_page,      item,      promotion  where cs_sold_date_sk = d_date_sk        and d_date between cast('1999-09-24' as date)                   and cast('1999-09-24' as date) + interval '30' day         and cs_catalog_page_sk = cp_catalog_page_sk        and cs_item_sk = i_item_sk        and i_current_price > 50        and cs_promo_sk = p_promo_sk        and p_channel_email = 'N'        and p_channel_tv = 'N'        and p_channel_radio = 'Y'        and p_channel_press = 'N'        and p_channel_event = 'Y'        and cs_wholesale_cost BETWEEN 33 AND 48        and i_category IN ('Home', 'Men') group by cp_catalog_page_id)  ,  wsr AS ( /*+ HashJoin(web_sales date_dim) HashJoin(web_sales item) */
select  web_site_id,           sum(ws_ext_sales_price) as sales,           sum(coalesce(wr_return_amt, 0)) as returns,           sum(ws_net_profit - coalesce(wr_net_loss, 0)) as profit   from web_sales left outer join web_returns on          (ws_item_sk = wr_item_sk and ws_order_number = wr_order_number),      date_dim,      web_site,      item,      promotion  where ws_sold_date_sk = d_date_sk        and d_date between cast('1999-09-24' as date)                   and cast('1999-09-24' as date) + interval '30' day         and ws_web_site_sk = web_site_sk        and ws_item_sk = i_item_sk        and i_current_price > 50        and ws_promo_sk = p_promo_sk        and p_channel_email = 'N'        and p_channel_tv = 'N'        and p_channel_radio = 'Y'        and p_channel_press = 'N'        and p_channel_event = 'Y'        and ws_wholesale_cost BETWEEN 33 AND 48        and i_category IN ('Home', 'Men') group by web_site_id)   select  channel         , id         , sum(sales) as sales         , sum(returns) as returns         , sum(profit) as profit  from  (select 'store channel' as channel         , 'store' || store_id as id         , sales         , returns         , profit  from   ssr  union all  select 'catalog channel' as channel         , 'catalog_page' || catalog_page_id as id         , sales         , returns         , profit  from  csr  union all  select 'web channel' as channel         , 'web_site' || web_site_id as id         , sales         , returns         , profit  from   wsr  ) x  group by rollup (channel, id)  order by channel          ,id  limit 100;
